import{_ as e,C as r,o as E,c as B,a2 as d,E as t}from"./chunks/framework.BnBoz4Zl.js";const p="/anjian-workbuddy-bluebook-site/assets/001_image_Ve9kbu40Eo.vWaCsND4.png",A="/anjian-workbuddy-bluebook-site/assets/002_image_IaB9bqqj6o.DVjSqHT7.png",m=JSON.parse('{"title":"第 1 章 初识 WorkBuddy","description":"WorkBuddy 是腾讯最新推出的全场景职场 AI 智能体工作台， 面向 人力资源、行政、运营、销售、研发等不同职场角色，是一款能够像真正同事一样思考、执行任务并交付结果的 AI 办公应用。","frontmatter":{},"headers":[],"relativePath":"bluebook/第一篇 使用手册：先把 WorkBuddy 用起来/第 1 章 初识 WorkBuddy/index.md","filePath":"bluebook/第一篇 使用手册：先把 WorkBuddy 用起来/第 1 章 初识 WorkBuddy/index.md","lastUpdated":1784290813000}'),s={name:"bluebook/第一篇 使用手册：先把 WorkBuddy 用起来/第 1 章 初识 WorkBuddy/index.md"};function n(i,o,_,u,k,l){const a=r("MermaidDiagram");return E(),B("div",null,[o[0]||(o[0]=d('<h1 id="第-1-章-初识-workbuddy" tabindex="-1">第 1 章 初识 WorkBuddy <a class="header-anchor" href="#第-1-章-初识-workbuddy" aria-label="Permalink to &quot;第 1 章 初识 WorkBuddy&quot;">​</a></h1><p><strong>WorkBuddy</strong> 是腾讯最新推出的全场景职场 AI 智能体工作台，</p><p>面向 人力资源、行政、运营、销售、研发等不同职场角色，是一款能够像真正同事一样思考、执行任务并交付结果的 AI 办公应用。</p><p><img src="'+p+'" alt="" loading="lazy"></p><h2 id="从-回答问题-到-交付结果" tabindex="-1">从“回答问题”到“交付结果” <a class="header-anchor" href="#从-回答问题-到-交付结果" aria-label="Permalink to &quot;从“回答问题”到“交付结果”&quot;">​</a></h2><p>与传统 AI 助手不同，WorkBuddy 不只是陪用户聊天、回答问题或者给出建议。</p><p>用户只需要用一句自然语言描述需求，它就可以理解任务目标，在本地电脑中自主规划执行步骤，并完成复杂的多模态任务。</p><p>在获得用户授权后，WorkBuddy 可以读取和处理本地文件，自动完成批量文件处理、文档生成、表格分析、PPT 制作、多模态内容创作、行业调研、本地知识库构建等工作。</p><p>对于更加复杂的任务，它还可以自主拆解步骤，并通过多个智能体（Agents）并行，减少人工在不同工具、文件和任务之间反复切换的成本。</p>',9)),t(a,{graph:"flowchart%20LR%0A%20%20%20%20A%5B%E8%AF%B4%E6%B8%85%E7%9B%AE%E6%A0%87%5D%20--%3E%20B%5B%E8%AF%BB%E5%8F%96%E6%8E%88%E6%9D%83%E8%B5%84%E6%96%99%5D%0A%20%20%20%20B%20--%3E%20C%5B%E6%8B%86%E8%A7%A3%E4%BB%BB%E5%8A%A1%E4%B8%8E%E9%80%89%E6%8B%A9%E5%B7%A5%E5%85%B7%5D%0A%20%20%20%20C%20--%3E%20D%5B%E6%89%A7%E8%A1%8C%E5%B9%B6%E7%94%9F%E6%88%90%E4%BA%A7%E7%89%A9%5D%0A%20%20%20%20D%20--%3E%20E%5B%E4%BA%BA%E5%B7%A5%E9%AA%8C%E6%94%B6%5D%0A%20%20%20%20E%20--%3E%7C%E4%B8%8D%E9%80%9A%E8%BF%87%7C%20F%5B%E6%8C%87%E5%87%BA%E9%97%AE%E9%A2%98%E5%B9%B6%E8%BF%94%E5%B7%A5%5D%0A%20%20%20%20F%20--%3E%20D%0A%20%20%20%20E%20--%3E%7C%E9%80%9A%E8%BF%87%7C%20G%5B%E5%BD%92%E6%A1%A3%E6%88%96%E5%8F%91%E5%B8%83%5D%0A"}),o[1]||(o[1]=d('<p>例如，用户可以直接告诉 WorkBuddy，分析这个文件夹中的销售数据，并生成一份汇报 PPT。</p><p><img src="'+A+'" alt="" loading="lazy"></p><p>WorkBuddy 会自主读取相关文件，理解数据内容，完成分析和总结，并生成最终可以查看和修改的工作成果。</p><p>整个过程中，用户不需要手动上传每一个文件，也不需要一步一步告诉 AI 下一步应该做什么。</p><p>WorkBuddy 面向的是完整的工作任务。</p><p>它的核心能力可以概括为三点，<strong>听得懂人话，能够自主思考规划，也真的能够操作电脑交付成果。</strong></p><p>为了完成不同类型的任务，WorkBuddy 还提供了多模型切换（混元/DeepSeek/GLM/Kimi/MiniMax 等）、MCP Server、Skills 技能包等能力。</p><p>用户可以根据不同任务选择合适的模型，也可以通过 MCP 和 Skills 扩展 WorkBuddy 的工具和专业能力。</p><p>同时，针对本地文件操作、终端执行等场景，WorkBuddy 还提供高危指令拦截和权限控制机制，降低 AI 自主执行过程中的风险。</p>',9))])}const c=e(s,[["render",n]]);export{m as __pageData,c as default};
